Introduce a `cancelled` boolean flag in the effect closure and check it inside the `fonts.ready.then()` callback before starting the RAF loop:

```ts
useEffect(() => {
  let animId: number;
  let cancelled = false;

  document.fonts.ready.then(() => {
    if (cancelled) return;  // component already unmounted
    const draw = () => {
      if (cancelled) return;
      // ... render logic ...
      animId = requestAnimationFrame(draw);
    };
    animId = requestAnimationFrame(draw);
  });

  return () => {
    cancelled = true;
    cancelAnimationFrame(animId);
  };
}, [...deps]);
```

Add a `catch` block to clear results and optionally surface an error:

```ts
const handleSearch = useCallback(
  async (value: string) => {
    setQuery(value);
    if (!user || value.trim().length < MIN_SEARCH_LENGTH) {
      setResults([]);
      return;
    }
    setIsSearching(true);
    try {
      const users = await searchUsers(supabase, value, user.id);
      setResults(users);
    } catch {
      setResults([]);  // clear stale results on error
    } finally {
      setIsSearching(false);
    }
  },
  [supabase, user],
);
```

Guard against empty email before accessing `email[0]`:

```ts
export function getInitials(name: string | null, email: string): string {
  if (name) {
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .toUpperCase()
      .slice(0, MAX_INITIALS_LENGTH);
  }
  if (!email) return "?";
  return email[0].toUpperCase();
}
```

